    {unstable_hash_object_v4, unstable_hash_object_v4}
    {unstable_hash_object_v4, unstable_hash_object_v4}
    {unstable_hash_object_v4, unstable_hash_object_v4}
    {unstable_hash_object_v4, unstable_hash_object_v4}
    for i_loop_1589 in {2, 1, 2, 3, 4, 5, 6, 8, 10, 9, 12, 10, 12, 13, 14, 15, 17, 17}:
        x, *y = tuple_v6
    x, *y = tuple_v6
for i_f1 in range(300):
